insert into tournois (id, nom, sport, description, photo_url, terrain_id, terrain_nom, terrain_ville, organisateur_id, organisateur_nom, date_debut, date_fin, date_cloture_inscription, prix_inscription, max_equipes, equipes_inscrites, taille_equipe, statut, region, departement) values ('to2', 'Summer Basket Cup', 'basket', 'Tournoi 3x3 en plein air. Format rapide, ambiance festive. DJ set + buvette sur place. Catégories Homme / Femme / Mixte. Les équipes jouent minimum 4 matchs garantis.', 'https://images.unsplash.com/photo-1546519638391-bb197d0bc7f5?w=900&auto=format', 't2', 'Palais des Sports de Paris', 'Paris', 'admin2', 'Paris Basket', ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '65 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '65 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '62 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), 2500, 32, 32, 3, 'complet', 'Île-de-France', 'Paris (75)');
insert into tournois (id, nom, sport, description, photo_url, terrain_id, terrain_nom, terrain_ville, organisateur_id, organisateur_nom, date_debut, date_fin, date_cloture_inscription, prix_inscription, max_equipes, equipes_inscrites, taille_equipe, statut, region, departement) values ('to3', 'Open Handball Montpellier', 'hand', 'Tournoi régional de handball avec équipes de toute l''Occitanie. Niveau Régionale et Nationale uniquement. Vestiaires et douches disponibles sur place.', 'https://images.unsplash.com/photo-1593341646782-e0b495cff86d?w=900&auto=format', 't3', 'Gymnase Montpellier Sud', 'Montpellier', 'admin3', 'Montpellier HB B', ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '99 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '100 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '93 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), 5000, 12, 4, 7, 'ouvert', 'Occitanie', 'Hérault (34)');
insert into tournois (id, nom, sport, description, photo_url, terrain_id, terrain_nom, terrain_ville, organisateur_id, organisateur_nom, date_debut, date_fin, date_cloture_inscription, prix_inscription, max_equipes, equipes_inscrites, taille_equipe, statut, region, departement) values ('to4', 'Volley Beach Marseille', 'volley', 'Tournoi de beach-volley sur sable importé. Ambiance bord de mer garantie. Paires mixtes uniquement. Prix en nature, coupes et médailles. Accès plage inclus.', 'https://images.unsplash.com/photo-1612872087720-bb876e2e67d1?w=900&auto=format', 't5', 'Palais des Sports de Marseille', 'Marseille', 'admin4', 'Marseille VB', ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '101 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '102 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '95 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), 3000, 24, 17, 4, 'ouvert', 'PACA', 'Bouches-du-Rhône (13)');
insert into tournois (id, nom, sport, description, photo_url, terrain_id, terrain_nom, terrain_ville, organisateur_id, organisateur_nom, date_debut, date_fin, date_cloture_inscription, prix_inscription, max_equipes, equipes_inscrites, taille_equipe, statut, region, departement) values ('to5', 'Tournoi des Champions Rennes', 'foot', 'Tournoi élite 11v11 sur pelouse naturelle. Retransmission live sur les réseaux sociaux. Équipes de niveau Régionale 1 minimum. Trophée + dotation pour le vainqueur.', 'https://images.unsplash.com/photo-1574629810360-7efbbe195018?w=900&auto=format', 't7', 'Roazhon Park', 'Rennes', 'admin5', 'Rennes FC B', ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '13 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '16 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '1 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), 8000, 8, 8, 11, 'complet', 'Bretagne', 'Ille-et-Vilaine (35)');
insert into tournois (id, nom, sport, description, photo_url, terrain_id, terrain_nom, terrain_ville, organisateur_id, organisateur_nom, date_debut, date_fin, date_cloture_inscription, prix_inscription, max_equipes, equipes_inscrites, taille_equipe, statut, region, departement) values ('to6', 'Lyon Basket Summer Jam', 'basket', '5v5 indoor sur parquet. Tournoi ouvert à tous niveaux. DJ, food trucks, concours de dunk. Trophées par catégorie.', 'https://images.unsplash.com/photo-1504450758481-7338eba7524a?w=900&auto=format', 't8', 'Gymnase Tony Bertrand', 'Lyon', 'admin6', 'Lyon Basket', ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '104 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '104 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '97 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), 3500, 16, 3, 5, 'ouvert', 'Auvergne-Rhône-Alpes', 'Rhône (69)');
insert into tournois (id, nom, sport, description, photo_url, terrain_id, terrain_nom, terrain_ville, organisateur_id, organisateur_nom, date_debut, date_fin, date_cloture_inscription, prix_inscription, max_equipes, equipes_inscrites, taille_equipe, statut, region, departement) values ('tol1', 'Lille Summer Volley Cup', 'volley', 'Le grand tournoi estival de volley-ball de la métropole lilloise. Format 6v6 indoor sur parquet. Arbitres officiels, trophées et médailles pour les 3 premières équipes. Ambiance garantie, buvette sur place toute la journée. Ouvert à tous les niveaux à partir de Régionale 2.', 'https://images.unsplash.com/photo-1612872087720-bb876e2e67d1?w=900&auto=format', 't22', 'Complexe Sportif Caulier', 'Lille', 'admin', 'Lille VBC', ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '68 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '69 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '62 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), 4500, 16, 7, 6, 'ouvert', 'Hauts-de-France', 'Nord (59)');
insert into tournois (id, nom, sport, description, photo_url, terrain_id, terrain_nom, terrain_ville, organisateur_id, organisateur_nom, date_debut, date_fin, date_cloture_inscription, prix_inscription, max_equipes, equipes_inscrites, taille_equipe, statut, region, departement) values ('tol2', 'Open Nord 4v4 — Beach Indoor', 'volley', 'Tournoi de volley 4v4 en salle sur sable aménagé. Format rapide et dynamique. Catégories Homme / Femme / Mixte. Chaque équipe dispute minimum 4 matchs. DJ set et food trucks. Idéal pour les clubs cherchant un format compétitif et festif.', 'https://images.unsplash.com/photo-1612872087720-bb876e2e67d1?w=900&auto=format', 't23', 'Salle Omnisports Porte de Valenciennes', 'Lille', 'admin', 'Flandres VB', ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '70 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '70 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), ((date_trunc('day', (now() at time zone 'Europe/Paris')) + interval '63 days' + interval '9 hours' + interval '0 minutes') at time zone 'Europe/Paris'), 3000, 24, 5, 4, 'ouvert', 'Hauts-de-France', 'Nord (59)');
